import{_ as d,o as r,c as a,a7 as e}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"世界观设定","description":"","frontmatter":{},"headers":[],"relativePath":"story/worldbuilding.md","filePath":"zh/story/worldbuilding.md","lastUpdated":1775394001000}'),o={name:"story/worldbuilding.md"};function h(n,t,s,l,i,b){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="世界观设定" tabindex="-1">世界观设定 <a class="header-anchor" href="#世界观设定" aria-label="Permalink to &quot;世界观设定&quot;">​</a></h1><h2 id="世界背景" tabindex="-1">世界背景 <a class="header-anchor" href="#世界背景" aria-label="Permalink to &quot;世界背景&quot;">​</a></h2><blockquote><p>这个世界正在死去。面对隐秘而不可名状的灾厄，弥萨格大学作为为数不多的知情者之一，决意唤醒与灾厄同源的力量，连结游走在疯狂边缘的人形武器，来抵抗这一场浩大的危机。</p></blockquote><p>忘却前夜的世界观深受 <strong>克苏鲁神话（Cthulhu Mythos）</strong> 影响，美术风格为<strong>迷雾英伦</strong>——维多利亚/爱德华时代风格融合洛夫克拉夫特恐怖元素。核心主题是<strong>记忆与遗忘</strong>——在铭记与遗忘之间的永恒挣扎。</p><blockquote><p>你并非什么救世主——只是一个走在疯狂边缘的人，一步步走向真相。</p></blockquote><h2 id="核心角色" tabindex="-1">核心角色 <a class="header-anchor" href="#核心角色" aria-label="Permalink to &quot;核心角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>称号</th><th>说明</th></tr></thead><tbody><tr><td><strong>守密人</strong></td><td>Secret Keeper</td><td>弥萨格大学的学生/特工。为调查失去记忆的原因，带领唤醒体构筑策略牌组，一步步调查诡异而疯狂的真相</td></tr><tr><td><strong>唤醒体</strong></td><td>Awakened One</td><td>游走在疯狂边缘的人形武器，与灾厄同源的力量载体。每位唤醒体都有独特的性格、背景故事和个人剧情任务</td></tr></tbody></table><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>忘却前夜</td><td>世界核心灾厄——周期性出现、威胁抹除记忆、身份乃至存在本身的超自然现象</td></tr><tr><td>唤醒体（Awakener）</td><td>与灾厄同源的力量载体，游走在疯狂边缘的人形武器</td></tr><tr><td>守密人（Keeper）</td><td>玩家所扮演的角色，弥萨格大学学生/特工</td></tr><tr><td>界域（Designated Realm）</td><td>四种不同的宇宙力量分类：混沌、深海、血肉、超维</td></tr><tr><td>算力（Arithmetica）</td><td>战斗中使用卡牌的能量，每回合基础5点</td></tr><tr><td>狂气（Aliemus）</td><td>与克苏鲁神话中「疯狂」概念对应的力量，累积至100点触发狂气爆发</td></tr><tr><td>银钥（Silver Key）</td><td>洛夫克拉夫特作品中的银钥意象，累积至1000点发动钥令</td></tr><tr><td>融蚀（Erosion）</td><td>数百年前降临的灾厄，抹灭一切被赋予「意义」的事物</td></tr></tbody></table><h2 id="四大界域" tabindex="-1">四大界域 <a class="header-anchor" href="#四大界域" aria-label="Permalink to &quot;四大界域&quot;">​</a></h2><table tabindex="0"><thead><tr><th>界域</th><th>灵感来源</th><th>特征</th></tr></thead><tbody><tr><td>混沌（Chaos）</td><td>阿撒托斯等混沌之神</td><td>无序、混搭、灵活</td></tr><tr><td>深海（Aequor）</td><td>克苏鲁、深潜者</td><td>海洋、触手、深渊</td></tr><tr><td>血肉（Caro）</td><td>奈亚拉托提普等</td><td>肉体、变异、吞噬</td></tr><tr><td>超维（Ultra）</td><td>高维存在</td><td>时空、维度、超越</td></tr></tbody></table><h2 id="核心灾厄-融蚀" tabindex="-1">核心灾厄：融蚀 <a class="header-anchor" href="#核心灾厄-融蚀" aria-label="Permalink to &quot;核心灾厄：融蚀&quot;">​</a></h2><p>数百年前，「融蚀」悄然降临。生命、理智、记忆，一切被人类赋予「意义」的东西，都在融蚀中被逐渐抹灭，不留痕迹，而人们对此一无所知。被融蚀感染的人会发生变异成为怪物，同时从世界中被彻底抹除——包括他人对其的所有记忆。</p><blockquote><p>欢迎来到弥萨格大学，守密人。但没有什么好恭喜的——你将无人知晓，无人嘉奖，无人铭记。</p></blockquote><h2 id="势力阵营" tabindex="-1">势力阵营 <a class="header-anchor" href="#势力阵营" aria-label="Permalink to &quot;势力阵营&quot;">​</a></h2><table tabindex="0"><thead><tr><th>势力</th><th>据点</th><th>定位</th></tr></thead><tbody><tr><td><strong>弥萨格大学</strong></td><td>狮子王国</td><td>玩家主阵营；为数不多知晓融蚀灾厄真相的组织</td></tr><tr><td><strong>雕塑家协会</strong></td><td>秘密</td><td>秘密运作的神秘组织</td></tr><tr><td><strong>持光者教会</strong></td><td>隐蔽——融蚀发生之处</td><td>在融蚀发生的地方隐秘活动的宗教组织</td></tr><tr><td><strong>航海者</strong></td><td>海洋/沿海地区</td><td>试图恢复沉没的古代王国雷姆利亚的海洋势力</td></tr><tr><td><strong>亚兰人</strong></td><td>雷姆瓦什沙漠（已消失）</td><td>来自沙漠的民族，隐藏在剧烈风暴中，已消失</td></tr><tr><td><strong>密斯提亚条约委员会</strong></td><td>全球各国设有办事处</td><td>跨国组织</td></tr><tr><td><strong>邪教组织</strong></td><td>各地</td><td>故事中遭遇的敌对势力</td></tr><tr><td><strong>融蚀体</strong></td><td>无固定</td><td>由融蚀现象创造的变异存在，含人型与协作型</td></tr></tbody></table><h2 id="重要地点" tabindex="-1">重要地点 <a class="header-anchor" href="#重要地点" aria-label="Permalink to &quot;重要地点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>地点</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>伦蒂尼恩</strong> (Londinium)</td><td>主要城市</td><td>维多利亚风格的主要城市，游戏核心舞台</td></tr><tr><td><strong>东区</strong></td><td>城市区域</td><td>伦蒂尼恩贫困区，忘却篇第一章舞台</td></tr><tr><td><strong>弥萨格大学</strong></td><td>机构</td><td>位于狮子王国，玩家主基地</td></tr><tr><td><strong>狮子王国</strong></td><td>国家</td><td>弥萨格大学主校区所在地</td></tr><tr><td><strong>雨镇</strong></td><td>城镇</td><td>支线故事「雨镇幽影」的舞台</td></tr><tr><td><strong>艾尔沃斯</strong> (Elworth)</td><td>异界地点</td><td>能自行重排的活体地点，会「呼唤」莉莉和Helot</td></tr><tr><td><strong>弥萨格黑潭</strong></td><td>异界地点</td><td>由萝坦守护，与塔薇的觉醒有关</td></tr><tr><td><strong>深渊海域</strong> (Aequor)</td><td>异界海洋</td><td>与深海界域相关的海洋领域</td></tr><tr><td><strong>雷姆利亚</strong> (Lemuria)</td><td>失落王国</td><td>沉没的古代王国，航海者试图恢复</td></tr><tr><td><strong>疗养院</strong></td><td>地点</td><td>第四章舞台，隐藏黑暗秘密</td></tr><tr><td><strong>无光秘境</strong></td><td>副本</td><td>解锁角色升星的挑战副本</td></tr></tbody></table><h2 id="角色神话原型" tabindex="-1">角色神话原型 <a class="header-anchor" href="#角色神话原型" aria-label="Permalink to &quot;角色神话原型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>神话原型</th><th>备注</th></tr></thead><tbody><tr><td>图鲁 (Tulu)</td><td>克苏鲁 (Cthulhu)</td><td>深海界域SSR，「幼主/沉睡之主」</td></tr><tr><td>雷娅 (Rhea)</td><td>黑山羊 (Shub-Niggurath)</td><td>血肉界域SSR，社区昵称「羊妈」</td></tr><tr><td>尤乌哈希 (Uuhashi)</td><td>约格-索托斯 (Yog-Sothoth)</td><td>血肉界域SSR</td></tr><tr><td>萝坦 (Lotan)</td><td>利维坦 / 海怪罗坦</td><td>初始SR/SSR，守护弥萨格黑潭</td></tr><tr><td>艾尔瓦 (Alva)</td><td>奈亚拉托提普 (Nyarlathotep)</td><td>混沌T0，可能参考外神使者形象</td></tr><tr><td>24</td><td>未知/原创</td><td>限定T0，以编号为名，身份神秘</td></tr></tbody></table><h2 id="联动活动" tabindex="-1">联动活动 <a class="header-anchor" href="#联动活动" aria-label="Permalink to &quot;联动活动&quot;">​</a></h2><table tabindex="0"><thead><tr><th>联动</th><th>合作方</th><th>说明</th></tr></thead><tbody><tr><td>沙耶之歌联动</td><td>沙耶之歌 (Saya no Uta)</td><td>与经典视觉小说《沙耶之歌》的跨界联动活动，添加了联动角色</td></tr></tbody></table><h2 id="主线剧情概览" tabindex="-1">主线剧情概览 <a class="header-anchor" href="#主线剧情概览" aria-label="Permalink to &quot;主线剧情概览&quot;">​</a></h2><p>主线剧情全文约<strong>80万字</strong>，以单元剧形式展开，分为两大篇章。</p><h3 id="忘却篇" tabindex="-1">忘却篇 <a class="header-anchor" href="#忘却篇" aria-label="Permalink to &quot;忘却篇&quot;">​</a></h3><p>序章至第七章。守密人初抵伦蒂尼恩，在弥萨格大学与初始四小只（朵尔、拉蒙娜、萝坦、奥吉尔）建立连结，逐步揭露融蚀灾厄背后的真相。</p><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>概要</th></tr></thead><tbody><tr><td>序章</td><td>序章</td><td>守密人初抵伦蒂尼恩，在弥萨格大学开启旅途。与初始四小只建立连结，初步了解融蚀灾厄的存在与唤醒体的本质</td></tr><tr><td>第一章</td><td>东区秘事</td><td>调查层层深入：先是工坊管理者，再到可疑医生，接着到疑似邪教组织。最终真相核心是一个被控制的可怜小女孩，她为保护家人和同伴选择了结束自己</td></tr><tr><td>第二章</td><td>蜕变</td><td>融蚀蜕变主题展开。守密人与唤醒体的羁绊逐渐加深，开始理解唤醒体并非单纯的武器，而是有血有肉的存在</td></tr><tr><td>第三章</td><td>第三章</td><td>多方势力角力渐趋白热化。雕塑家协会、持光者教会等组织纷纷浮出水面，弥萨格大学的真实动机也开始令人生疑</td></tr><tr><td>第四章</td><td>第四章</td><td>重大转折点。守密人将救出的少女莉莉带到疗养院，却发现更大的危机潜伏其中</td></tr><tr><td>第五章</td><td>第五章</td><td>多线剧情汇聚收束。前几章埋下的伏笔逐一揭晓，各阵营的计划开始碰撞</td></tr><tr><td>第六章</td><td>第六章</td><td>各阵营摊牌，守密人开始质疑「保护真相」的代价。融蚀的本质进一步揭露</td></tr><tr><td>第七章</td><td>第七章</td><td>忘却篇终章。包含7-18「火种(Kindling)」等Boss关卡。守密人面临遗忘与铭记的终极考验</td></tr></tbody></table><h3 id="星辰篇" tabindex="-1">星辰篇 <a class="header-anchor" href="#星辰篇" aria-label="Permalink to &quot;星辰篇&quot;">​</a></h3><p>忘却篇落幕后开启的新篇章。新的星辰力量改变了世界格局，唤醒体们在星辰之力影响下发生蜕变。</p><table tabindex="0"><thead><tr><th>章节</th><th>标题</th><th>关卡</th><th>概要</th></tr></thead><tbody><tr><td>序章</td><td>星辰篇序章</td><td>--</td><td>世界格局发生巨变，新的威胁和盟友同时出现</td></tr><tr><td>第一章</td><td>星辰正位之刻</td><td>1-1至1-14</td><td>唤醒体们在星辰之力的影响下发生变化，守密人需要重新理解伙伴的本质</td></tr><tr><td>第二章</td><td>蜕变</td><td>2-1至2-18</td><td>与忘却篇同名章节遥相呼应，但蜕变含义更加深远——星之力量带来内在觉醒</td></tr><tr><td>第三章</td><td>第三章</td><td>3-1至3-11</td><td>预言中隐藏的真相逐渐揭开，星辰的指引背后似乎隐藏着更宏大的计划</td></tr><tr><td>第四章</td><td>乐园</td><td>4-0至4-16</td><td>难度跃升最大的章节。「为何黑日遮蔽了天空？」黑日意象贯穿全章，终极Boss战难度极高</td></tr></tbody></table>',30)])])}const c=d(o,[["render",h]]);export{u as __pageData,c as default};
